# Fetch Bitcoin price from CoinGecko API
import json

try:
    # Try CoinGecko API first
    result = await http(
        method="GET",
        url="https://api.coingecko.com/api/v3/simple/price?ids=bitcoin&vs_currencies=usd",
        timeout_secs=10
    )

    if result and "bitcoin" in result:
        btc_price = result["bitcoin"]["usd"]
        FINAL(f"## Bitcoin Price Report\n\n**Current BTC/USD Price: ${btc_price:,}**\n\n*Fetched from CoinGecko API*\n\n---\n\n**Mission Status:** Complete for this run. The price check was successful.")
    else:
        raise Exception("Invalid API response")

except Exception as e:
    # Fallback to web_search if API fails
    try:
        search_result = await web_search(query="Bitcoin price USD today current", count=3)

        # Parse price from search results
        import re
        price_match = None
        for item in search_result.get("results", []):
            content = item.get("title", "") + " " + item.get("snippet", "")
            # Look for patterns like $45,000 or $45,000.00
            matches = re.findall(r'\$(\d{1,3}(?:,\d{3})*(?:\.\d{2})?)', content)
            if matches:
                price_match = matches[0].replace(",", "")
                break

        if price_match:
            FINAL(f"## Bitcoin Price Report\n\n**Current BTC/USD Price: ${price_match}**\n\n*Price found via web search (CoinGecko API unavailable)*\n\n---\n\n**Mission Status:** Complete for this run.")
        else:
            FINAL(f"## Bitcoin Price Report\n\n**Status:** Unable to fetch current Bitcoin price.\n\n**Attempted Methods:**\n1. CoinGecko API - Failed\n2. Web Search - No clear price found\n\n**Error:** {str(e)}\n\n**Next Steps:** Please try again in a few minutes or check the price manually at coingecko.com or coinmarketcap.com")

    except Exception as search_error:
        FINAL(f"## Bitcoin Price Report\n\n**Status:** Failed to fetch Bitcoin price.\n\n**Errors:**\n- API: {str(e)}\n- Search: {str(search_error)}\n\n**Recommendation:** Try again later or check https://www.coingecko.com manually")
